-- ============================================
-- Hilton Honors Database - Table Creation
-- IT222 Database Principles Project
-- ============================================

-- CUSTOMER Table
CREATE TABLE "CUSTOMER"
(
    "CUSTOMER_ID" NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY
        MINVALUE 1 MAXVALUE 9999999999999999999999999999
        INCREMENT BY 1 START WITH 1
        CACHE 20 NOORDER NOCYCLE NOKEEP NOSCALE
        NOT NULL ENABLE,
    "NAME"  VARCHAR2(50 CHAR) NOT NULL ENABLE,
    "PHONE" VARCHAR2(10 CHAR) NOT NULL ENABLE,
    "EMAIL" VARCHAR2(100 CHAR) NOT NULL ENABLE,
    CONSTRAINT "CUSTOMER_PK" PRIMARY KEY ("CUSTOMER_ID")
        USING INDEX ENABLE
);

-- ROOM Table
CREATE TABLE "ROOM"
(
    "ROOM_NUMBER" NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY
        MINVALUE 1 MAXVALUE 9999999999999999999999999999
        INCREMENT BY 1 START WITH 1
        CACHE 20 NOORDER NOCYCLE NOKEEP NOSCALE
        NOT NULL ENABLE,
    "TYPE"   VARCHAR2(20 CHAR) NOT NULL ENABLE,
    "PRICE"  NUMBER NOT NULL ENABLE,
    "STATUS" VARCHAR2(15 CHAR) NOT NULL ENABLE,
    CONSTRAINT "ROOM_PK" PRIMARY KEY ("ROOM_NUMBER")
        USING INDEX ENABLE
);

-- EMPLOYEE Table
CREATE TABLE "EMPLOYEE"
(
    "EMPLOYEE_ID" NUMBER(10,0) GENERATED BY DEFAULT ON NULL AS IDENTITY
        MINVALUE 1 MAXVALUE 9999999999999999999999999999
        INCREMENT BY 1 START WITH 1
        CACHE 20 NOORDER NOCYCLE NOKEEP NOSCALE
        NOT NULL ENABLE,
    "NAME"     VARCHAR2(50 CHAR) NOT NULL ENABLE,
    "JOBTITLE" VARCHAR2(30 CHAR),
    CONSTRAINT "EMPLOYEE_PK" PRIMARY KEY ("EMPLOYEE_ID")
        USING INDEX ENABLE
);

-- RESERVATION Table
CREATE TABLE "RESERVATION"
(
    "RESERVATION_ID" NUMBER(10,0) GENERATED BY DEFAULT ON NULL AS IDENTITY
        MINVALUE 1 MAXVALUE 9999999999999999999999999999
        INCREMENT BY 1 START WITH 1
        CACHE 20 NOORDER NOCYCLE NOKEEP NOSCALE
        NOT NULL ENABLE,
    "CHECK_INDATE"   DATE NOT NULL ENABLE,
    "CHECK_OUT_DATE" DATE NOT NULL ENABLE,
    "TOTALPRICE"     NUMBER NOT NULL ENABLE,
    "CUSTOMER_ID"    NUMBER,
    "ROOM_NUMBER"    NUMBER,
    "EMPLOYEE_ID"    NUMBER,
    CONSTRAINT "RESERVATION_PK" PRIMARY KEY ("RESERVATION_ID")
        USING INDEX ENABLE
);

-- Foreign Key Constraints for RESERVATION
ALTER TABLE "RESERVATION" ADD CONSTRAINT "RES_CUSTOMER_FK"
    FOREIGN KEY ("CUSTOMER_ID") REFERENCES "CUSTOMER" ("CUSTOMER_ID") ENABLE;

ALTER TABLE "RESERVATION" ADD CONSTRAINT "RES_EMPLOYEE_FK"
    FOREIGN KEY ("EMPLOYEE_ID") REFERENCES "EMPLOYEE" ("EMPLOYEE_ID") ENABLE;

ALTER TABLE "RESERVATION" ADD CONSTRAINT "RES_ROOM_FK"
    FOREIGN KEY ("ROOM_NUMBER") REFERENCES "ROOM" ("ROOM_NUMBER") ENABLE;
